<?php
require_once __DIR__ . '/../core/db.php'; require_once __DIR__ . '/../core/functions.php'; require_once __DIR__ . '/../core/security.php'; require_once __DIR__ . '/../core/auth.php'; require_once __DIR__ . '/../core/inventory.php';
start_secure_session(); require_admin(); ensure_inventory_module_schema();
$branchId=(int)($_GET['branch_id'] ?? active_branch_id());
$branches=inventory_branches();
$purchase=db()->prepare("SELECT ph.purchase_date, ph.purchase_no, s.supplier_name, ph.grand_total FROM purchase_headers ph JOIN suppliers s ON s.id=ph.supplier_id WHERE ph.branch_id=? ORDER BY ph.purchase_date DESC, ph.id DESC LIMIT 100"); $purchase->execute([$branchId]); $purchaseRows=$purchase->fetchAll();
$consume=db()->prepare("SELECT ph.production_date, ph.production_no, p.name AS material_name, pi.actual_qty FROM production_headers ph JOIN production_items pi ON pi.production_id=ph.id JOIN products p ON p.id=pi.material_product_id WHERE ph.branch_id=? AND ph.status='posted' ORDER BY ph.id DESC LIMIT 200"); $consume->execute([$branchId]); $consumeRows=$consume->fetchAll();
$output=db()->prepare("SELECT ph.production_date, ph.production_no, p.name AS finished_name, ph.qty_to_produce, ph.mode_source FROM production_headers ph JOIN products p ON p.id=ph.finished_product_id WHERE ph.branch_id=? AND ph.status='posted' ORDER BY ph.id DESC LIMIT 100"); $output->execute([$branchId]); $outputRows=$output->fetchAll();
$auto=db()->prepare("SELECT spl.transaction_code, ph.production_no, ph.production_date FROM sales_production_links spl JOIN production_headers ph ON ph.id=spl.production_id WHERE spl.branch_id=? ORDER BY spl.id DESC LIMIT 100"); $auto->execute([$branchId]); $autoRows=$auto->fetchAll();
$card=db()->prepare("SELECT sl.created_at, p.name, sl.trans_type, sl.qty_in, sl.qty_out, sl.note FROM stock_ledger sl JOIN products p ON p.id=sl.product_id WHERE sl.branch_id=? ORDER BY sl.id DESC LIMIT 200"); $card->execute([$branchId]); $cardRows=$card->fetchAll();
$customCss=setting('custom_css','');
?>
<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Laporan Inventory</title><link rel="icon" href="<?php echo e(favicon_url()); ?>"><link rel="stylesheet" href="<?php echo e(asset_url('assets/app.css')); ?>"><style><?php echo $customCss; ?></style></head><body><div class="container"><?php include __DIR__ . '/partials_sidebar.php'; ?><div class="main"><div class="topbar"><button class="btn" data-toggle-sidebar type="button">Menu</button></div><div class="content"><div class="card"><form><label>Cabang</label><select name="branch_id"><?php foreach($branches as $b): ?><option value="<?php echo e((string)$b['id']); ?>" <?php echo (int)$b['id']===$branchId?'selected':''; ?>><?php echo e($b['branch_name']); ?></option><?php endforeach; ?></select> <button class="btn" type="submit">Filter</button></form></div><div class="card"><h3>Pembelian Bahan Baku</h3><table class="table"><thead><tr><th>Tanggal</th><th>No</th><th>Supplier</th><th>Total</th></tr></thead><tbody><?php foreach($purchaseRows as $r): ?><tr><td><?php echo e($r['purchase_date']); ?></td><td><?php echo e($r['purchase_no']); ?></td><td><?php echo e($r['supplier_name']); ?></td><td><?php echo e(format_number_id((float)$r['grand_total'])); ?></td></tr><?php endforeach; ?></tbody></table></div><div class="card"><h3>Pemakaian Bahan Produksi</h3><table class="table"><thead><tr><th>Tanggal</th><th>No Produksi</th><th>Material</th><th>Qty</th></tr></thead><tbody><?php foreach($consumeRows as $r): ?><tr><td><?php echo e($r['production_date']); ?></td><td><?php echo e($r['production_no']); ?></td><td><?php echo e($r['material_name']); ?></td><td><?php echo e(format_number_id((float)$r['actual_qty'])); ?></td></tr><?php endforeach; ?></tbody></table></div><div class="card"><h3>Hasil Produksi</h3><table class="table"><thead><tr><th>Tanggal</th><th>No</th><th>Produk</th><th>Qty</th><th>Mode</th></tr></thead><tbody><?php foreach($outputRows as $r): ?><tr><td><?php echo e($r['production_date']); ?></td><td><?php echo e($r['production_no']); ?></td><td><?php echo e($r['finished_name']); ?></td><td><?php echo e(format_number_id((float)$r['qty_to_produce'])); ?></td><td><?php echo e($r['mode_source']); ?></td></tr><?php endforeach; ?></tbody></table></div><div class="card"><h3>Riwayat Auto Production POS</h3><table class="table"><thead><tr><th>Transaction</th><th>No Produksi</th><th>Tanggal</th></tr></thead><tbody><?php foreach($autoRows as $r): ?><tr><td><?php echo e($r['transaction_code']); ?></td><td><?php echo e($r['production_no']); ?></td><td><?php echo e($r['production_date']); ?></td></tr><?php endforeach; ?></tbody></table></div><div class="card"><h3>Kartu Stok / Ledger</h3><table class="table"><thead><tr><th>Waktu</th><th>Produk</th><th>Tipe</th><th>In</th><th>Out</th><th>Catatan</th></tr></thead><tbody><?php foreach($cardRows as $r): ?><tr><td><?php echo e($r['created_at']); ?></td><td><?php echo e($r['name']); ?></td><td><?php echo e($r['trans_type']); ?></td><td><?php echo e(format_number_id((float)$r['qty_in'])); ?></td><td><?php echo e(format_number_id((float)$r['qty_out'])); ?></td><td><?php echo e($r['note']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div></div><script defer src="<?php echo e(asset_url('assets/app.js')); ?>"></script></body></html>
